// Parse and validate incoming warranty claim data
const input = $input.first().json;
let formData = input.body || input;

const extractField = (data, fieldName) => {
  if (data[`contact[${fieldName}]`]) return data[`contact[${fieldName}]`];
  if (data[fieldName]) return data[fieldName];
  if (data.contact && data.contact[fieldName]) return data.contact[fieldName];
  return null;
};

const formatPhoneNumber = (phone) => {
  if (!phone) return null;
  let cleaned = phone.replace(/[^\d+]/g, '');
  if (!cleaned || cleaned.replace(/\+/g, '').length === 0) return null;

  if (cleaned.startsWith('0') && cleaned.length === 11) {
    cleaned = '+44' + cleaned.substring(1);
  } else if (cleaned.startsWith('44') && cleaned.length === 12) {
    cleaned = '+' + cleaned;
  } else if (cleaned.startsWith('+44') || cleaned.startsWith('+')) {
    // Already has international prefix
  } else if (cleaned.length === 10 && !cleaned.startsWith('0')) {
    cleaned = '+44' + cleaned;
  } else if (cleaned.length >= 7 && cleaned.length <= 15) {
    cleaned = '+' + cleaned;
  } else {
    return null;
  }

  const digitsOnly = cleaned.replace('+', '');
  if (digitsOnly.length < 7 || digitsOnly.length > 15) return null;
  if (!/^\+\d{7,15}$/.test(cleaned)) return null;
  return cleaned;
};

// Extract fields
const name = extractField(formData, 'name');
const email = extractField(formData, 'email');
const phone = extractField(formData, 'phone');
const repairDate = extractField(formData, 'repair_date');
const deviceType = extractField(formData, 'device_type');
const model = extractField(formData, 'model');
const issue = extractField(formData, 'body');

// Validation
if (!email) throw new Error('Email is required');
if (!name) throw new Error('Name is required');
if (!deviceType) throw new Error('Device type is required');
if (!issue) throw new Error('Issue description is required');

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(email.trim())) throw new Error('Invalid email format');

const formattedPhone = formatPhoneNumber(phone);
const uniqueId = Date.now();

// Build device string
const deviceStr = model ? `${deviceType} ${model}` : deviceType;

// Email subject - unique for conversation matching
const emailSubject = `Warranty Claim: ${name} - ${deviceStr} [${uniqueId}]`;

// Email body
let emailBody = `Warranty Claim from ${name}`;
emailBody += `\n\nEmail: ${email}`;
emailBody += `\nPhone: ${formattedPhone || 'Not provided'}`;
emailBody += `\nDevice: ${deviceStr}`;
if (repairDate) emailBody += `\nApprox. Repair Date: ${repairDate}`;
emailBody += `\n\nIssue Description:\n${issue}`;

return {
  json: {
    name: name.trim(),
    email: email.trim().toLowerCase(),
    phone: formattedPhone,
    repairDate: repairDate || null,
    deviceType: deviceType,
    model: model || null,
    deviceStr: deviceStr,
    issue: issue,
    emailSubject: emailSubject,
    emailBody: emailBody,
    uniqueId: uniqueId,
    timestamp: new Date().toISOString()
  }
};

// Extract conversation ID and original contact ID
const searchResult = $input.first().json;

// Get contact ID from whichever path ran (Use Existing Contact or Use New Contact)
let customerContactId = null;
try {
  customerContactId = $('Use Existing Contact').first().json.customerContactId;
} catch(e) {
  // Existing contact path didn't run, try new contact path
}
if (!customerContactId) {
  try {
    customerContactId = $('Use New Contact').first().json.customerContactId;
  } catch(e) {
    // Neither path produced an ID
  }
}

if (!searchResult.conversations || searchResult.conversations.length === 0) {
  return {
    json: {
      conversationId: null,
      originalContactId: null,
      customerContactId: customerContactId,
      error: 'Conversation not found'
    }
  };
}

const conversation = searchResult.conversations[0];
const conversationId = conversation.id;

let originalContactId = null;
if (conversation.contacts && conversation.contacts.contacts && conversation.contacts.contacts.length > 0) {
  originalContactId = conversation.contacts.contacts[0].id;
}

return {
  json: {
    conversationId: conversationId,
    originalContactId: originalContactId,
    customerContactId: customerContactId
  }
};

